solution: ```class Solution {
    public String reverseWords(String s) {
        char[] a = s.toCharArray();
        int n = a.length;
        reverse(a, 0, n - 1);
        int store = 0;
        int i = 0;
        while (i < n) {
            while (i < n && a[i] == ' ') i++;
            if (i == n) break;
            int start = i;
            while (i < n && a[i] != ' ') i++;
            reverse(a, start, i - 1);
            if (store != 0) a[store++] = ' ';
            for (int j = start; j < i; j++) a[store++] = a[j];
        }
        return new String(a, 0, store);
    }
    private void reverse(char[] a, int l, int r) {
        while (l < r) {
            char tmp = a[l];
            a[l++] = a[r];
            a[r--] = tmp;
        }
    }
}```
